const yearEl=document.getElementById("year");yearEl&&(yearEl.textContent=(new Date).getFullYear());const navToggle=document.getElementById("navToggle"),navLinks=document.getElementById("navLinks");navToggle&&navLinks&&(navToggle.addEventListener("click",()=>{const e=navLinks.classList.toggle("is-open");navToggle.classList.toggle("is-open",e),navToggle.setAttribute("aria-expanded",String(e))}),navLinks.querySelectorAll("a").forEach(e=>{e.addEventListener("click",()=>{navLinks.classList.remove("is-open"),navToggle.classList.remove("is-open"),navToggle.setAttribute("aria-expanded","false")})}));const revealEls=document.querySelectorAll(".reveal");if("IntersectionObserver"in window&&revealEls.length){const e=new IntersectionObserver(t=>{t.forEach(t=>{t.isIntersecting&&(t.target.classList.add("is-visible"),e.unobserve(t.target))})},{threshold:.12,rootMargin:"0px 0px -40px 0px"});revealEls.forEach(t=>e.observe(t))}else revealEls.forEach(e=>e.classList.add("is-visible"));const sections=document.querySelectorAll("main section[id]"),navAnchors=document.querySelectorAll(".nav-links a[data-nav]");if("IntersectionObserver"in window&&sections.length&&navAnchors.length){const e=new IntersectionObserver(e=>{e.forEach(e=>{if(e.isIntersecting){const t=e.target.getAttribute("id");navAnchors.forEach(e=>{e.classList.toggle("active",e.getAttribute("href")===`#${t}`)})}})},{rootMargin:"-45% 0px -45% 0px"});sections.forEach(t=>e.observe(t))}